        objective_id: String,
        detail: String,
        max_tasks: i64,
        max_runs: i64,
        deadline_at_ms: i64,
    },
    ObjectiveStatus { root: PathBuf, objective_id: String },
    Objectives { root: PathBuf },
    TaskCreate {
