/run/current-system/sw/bin/bash -lc 'tmpdir=$(mktemp -d)
cat >"$tmpdir/source.json" <<'"'EOF'
{\"compatibility\":{\"interfaceFingerprint\":\"abc\",\"migration\":{\"strategy\":\"none\"}},\"decls\":[{\"name\":\"main\",\"bodyText\":\"x\",\"keep\":1}]}
EOF
cat >\""'$tmpdir/structured.json" <<'"'EOF'
{\"decls\":[{\"name\":\"main\",\"bodyText\":\"x\",\"keep\":1}]}
EOF
NODE=node bash -lc '
  source_path=\""'$1"
  migrating_output_path="$2"
  incompatible_output_path="$3"
  structured_source_path="$4"
  structured_output_path="$5"
  node_bin="${NODE:-node}"
  "$node_bin" - "$source_path" "$migrating_output_path" "$incompatible_output_path" "$structured_source_path" "$structured_output_path" "$structured_source_path" "$structured_output_path" "$structured_source_path" "$structured_output_path" <<'"'\"'\"'NODE'\"'\"'
const fs = require(\"fs\");
const [sourcePath, migratingOutputPath, incompatibleOutputPath, helloSourcePath, helloStructuredOutputPath] = process.argv.slice(2);
const writeJson = (outputPath, payload) => fs.writeFileSync(outputPath, "'`${JSON.stringify(payload)}'"\\n"'`, "utf8");
const payload = JSON.parse(fs.readFileSync(sourcePath, "utf8"));
const originalFingerprint = payload.compatibility.interfaceFingerprint;
const migratingPayload = structuredClone(payload);
migratingPayload.compatibility.interfaceFingerprint = `${originalFingerprint}-upgrade`;
migratingPayload.compatibility.acceptedPreviousFingerprints = [originalFingerprint];
migratingPayload.compatibility.migration.strategy = "state-handoff";
writeJson(migratingOutputPath, migratingPayload);
const incompatiblePayload = structuredClone(migratingPayload);
incompatiblePayload.compatibility.acceptedPreviousFingerprints = ["native-compat:incompatible"];
writeJson(incompatibleOutputPath, incompatiblePayload);
const structuredPayload = JSON.parse(fs.readFileSync(helloSourcePath, "utf8"));
for (const decl of structuredPayload.decls ?? []) delete decl.bodyText;
writeJson(helloStructuredOutputPath, structuredPayload);
NODE
'"' _ \""'$tmpdir/source.json" "$tmpdir/migrating.json" "$tmpdir/incompatible.json" "$tmpdir/structured.json" "$tmpdir/structured-out.json"
node -e '"'const fs=require(\"fs\"); const migrated=JSON.parse(fs.readFileSync(process.argv[1],\"utf8\")); const incompatible=JSON.parse(fs.readFileSync(process.argv[2],\"utf8\")); const structured=JSON.parse(fs.readFileSync(process.argv[3],\"utf8\")); if (migrated.compatibility.interfaceFingerprint "'!== "abc-upgrade") process.exit(1); if (migrated.compatibility.acceptedPreviousFingerprints[0] !== "abc") process.exit(1); if (migrated.compatibility.migration.strategy !== "state-handoff") process.exit(1); if (incompatible.compatibility.acceptedPreviousFingerprints[0] !== "native-compat:incompatible") process.exit(1); if (Object.hasOwn(structured.decls[0], "bodyText")) process.exit(1);'"' \""'$tmpdir/migrating.json" "$tmpdir/incompatible.json" "$tmpdir/structured-out.json"
rm -rf "$tmpdir"'

